import { useState } from "react";
import { T } from "../../assets/styles/theme";
import { Btn, Modal, Input, Select } from "../../components/UI";
import { login, registerUser } from "../../api/auth";
// ─── ROLE LOGIN CARDS CONFIG ──────────────────────────────────────────────────
// 4 cards shown in parallel - hover zooms in selected, shrinks others
const ROLES = [
  { key: "student",  icon: "👨‍🎓", label: "Student",  sub: "Access courses, assignments & performance",  color: T.accent,   bg: "linear-gradient(135deg,#011F2B,#02485E)" },
  { key: "teacher",  icon: "👨‍🏫", label: "Teacher",  sub: "Manage courses, students & classes",         color: T.accentG,  bg: "linear-gradient(135deg,#001A0E,#01321A)" },
  { key: "parent",   icon: "👨‍👩‍👦", label: "Parent",   sub: "Track your child's progress & fees",         color: T.accentR,  bg: "linear-gradient(135deg,#1A0005,#2D0010)" },
  { key: "admin",    icon: "🛡️",  label: "Admin",    sub: "Full system control & analytics",             color: T.accentY,  bg: "linear-gradient(135deg,#1A1200,#2D2000)" },
];

// ─── REGISTRATION FORM FIELDS PER ROLE ────────────────────────────────────────
const REG_FIELDS = {
  student: [
    { label: "Student Name *", placeholder: "Full name" },
    { label: "Email Address *", type: "email", placeholder: "student@email.com" },
    { label: "Password *", type: "password", placeholder: "Min 8 characters" },
    { label: "Confirm Password *", type: "password", placeholder: "Repeat password" },
  ],
  teacher: [
    { label: "Teacher Name *", placeholder: "Full name" },
    { label: "Email Address *", type: "email", placeholder: "teacher@email.com" },
    { label: "Password *", type: "password", placeholder: "Min 8 characters" },
    { label: "Confirm Password *", type: "password", placeholder: "Repeat password" },
  ],
  parent: [
    { label: "Parent Name *", placeholder: "Full name" },
    { label: "Email Address *", type: "email", placeholder: "parent@email.com" },
    { label: "Password *", type: "password", placeholder: "Min 8 characters" },
    { label: "Confirm Password *", type: "password", placeholder: "Repeat password" },
  ],
  admin: [
    { label: "Admin Name *", placeholder: "Full name" },
    { label: "Academy Name *", placeholder: "Academy / Institute name" },
    { label: "Referral ID (Administrator Head) *", placeholder: "Enter Administrator Head referral ID" },
    { label: "Gender", type: "select", options: ["Male", "Female", "Other"] },
    { label: "Email Address *", type: "email", placeholder: "admin@email.com" },
    { label: "Password *", type: "password", placeholder: "Min 8 characters" },
    { label: "Confirm Password *", type: "password", placeholder: "Repeat password" },
  ],
};

// ─── REGISTRATION MODAL ───────────────────────────────────────────────────────
const RegModal = ({ role, onClose, onSuccess }) => {
  const fields = REG_FIELDS[role] || [];
  const [form, setForm] = useState({});
  const handleChange = (label) => (e) => {
    setForm((f) => ({ ...f, [label]: e.target.value }));
  };
  const handleSubmit = async () => {
    try {
      const base = {
        name:
          form["Student Name *"] ||
          form["Teacher Name *"] ||
          form["Parent Name *"] ||
          form["Admin Name *"] ||
          "",
        email: form["Email Address *"] || "",
        password: form["Password *"] || "",
        role:
          role === "student"
            ? "STUDENT"
            : role === "teacher"
            ? "TEACHER"
            : role === "parent"
            ? "PARENT"
            : "ADMIN",
      };
      const extra =
        role === "admin"
          ? {
              academyName: form["Academy Name *"] || "",
              referralId:
                form["Referral ID (Administrator Head) *"] || "",
              gender: form["Gender"] || null,
            }
          : {
              gender: form["Gender"] || null,
            };
      const payload = { ...base, ...extra };
      const auth = await registerUser(payload); // AuthResponse
      onSuccess(auth);
    } catch (err) {
      alert(err.message || "Registration failed");
    }
  };
  const title =
    role.charAt(0).toUpperCase() + role.slice(1) + " Registration";
  return (
    <Modal open title={title} onClose={onClose}>
      <p style={{ fontSize: 12, color: T.muted, marginBottom: 20 }}>
        {role === "admin"
          ? "⚠️ Admin registration requires a valid Super Admin Referral ID (Administrator Head user code)."
          : "Create your account to get started."}
      </p>
      <Input
        label="ID (Auto-generated)"
        placeholder="AUTO-GENERATED BY SYSTEM"
        style={{ opacity: 0.5 }}
        value=""
        onChange={() => {}}
      />
      {fields.map((f) =>
        f.type === "select" ? (
          <Select
            key={f.label}
            label={f.label}
            options={f.options.map((o) => ({ value: o, label: o }))}
            value={form[f.label] || ""}
            onChange={handleChange(f.label)}
          />
        ) : (
          <Input
            key={f.label}
            label={f.label}
            type={f.type || "text"}
            placeholder={f.placeholder}
            value={form[f.label] || ""}
            onChange={handleChange(f.label)}
          />
        )
      )}
      <Btn variant="primary" full size="lg" onClick={handleSubmit}>
        Create Account →
      </Btn>
    </Modal>
  );
};

// ─── LOGIN PAGE ───────────────────────────────────────────────────────────────
// Shows 4 login boxes in parallel with zoom-in/zoom-out animation on hover
// Login works with email and password
const LoginPage = ({ onLoginSuccess, onBack }) => {
  const [zoomed, setZoomed] = useState(null);
  const [modal, setModal] = useState(null);
  const [credentials, setCredentials] = useState({
    student: { email: "", password: "" },
    teacher: { email: "", password: "" },
    parent:  { email: "", password: "" },
    admin:   { email: "", password: "" },
  });
  const [loadingRole, setLoadingRole] = useState(null);
  const handleFieldChange = (roleKey, field) => (e) => {
    const value = e.target.value;
    setCredentials((prev) => ({
      ...prev,
      [roleKey]: { ...prev[roleKey], [field]: value },
    }));
  };
  const handleLoginClick = async (roleKey) => {
    try {
      setLoadingRole(roleKey);
      const { email, password } = credentials[roleKey];
      const auth = await login(email, password, roleKey);
      localStorage.setItem("token", auth.token || auth.data?.token);
 // AuthResponse
      onLoginSuccess(auth);
    } catch (err) {
      alert(err.message || "Login failed");
    } finally {
      setLoadingRole(null);
    }
  };

  return (
    <div style={{ minHeight: "100vh", background: T.bg, display: "flex", flexDirection: "column" }}>
      {/* Header */}
      <div style={{ padding: "0 40px", height: 64, display: "flex", alignItems: "center", justifyContent: "space-between", borderBottom: `1px solid ${T.border}`, background: "rgba(6,4,15,.8)", backdropFilter: "blur(20px)" }}>
        <div style={{ fontFamily: "Syne", fontSize: 18, fontWeight: 900, display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ width: 32, height: 32, background: `linear-gradient(135deg, ${T.primary}, ${T.accent})`, borderRadius: 8, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 14 }}>🎓</div>
          Zenelait<span style={{ color: T.accent }}>InfoTech</span>
        </div>
        <Btn variant="ghost" size="sm" onClick={onBack}>← Back to Website</Btn>
      </div>

      {/* Content */}
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "40px 20px", background: `radial-gradient(ellipse 80% 80% at 50% 50%, rgba(124,58,237,.12), transparent 70%)` }}>
        <div style={{ textAlign: "center", marginBottom: 44, animation: "fadeUp .5s ease" }}>
          <div style={{ fontFamily: "Syne", fontSize: "clamp(26px,4vw,42px)", fontWeight: 900, marginBottom: 8 }}>
            Welcome to <span style={{ color: T.accent }}>Zenelait</span> LMS
          </div>
          <p style={{ color: T.muted, fontSize: 14 }}>Hover over your role and sign in to continue</p>
        </div>

        {/* 4 Parallel Login Cards with zoom animation */}
        <div style={{ display: "flex", gap: 18, width: "100%", maxWidth: 1100 }}>
          {ROLES.map(role => {
            const isZoomed = zoomed === role.key;
            const isShrunk = zoomed && zoomed !== role.key;
            return (
              <div key={role.key}
                style={{
                  flex: isZoomed ? 2.4 : isShrunk ? .55 : 1,
                  minHeight: 420, borderRadius: 20, overflow: "hidden", cursor: "pointer",
                  border: `1px solid ${isZoomed ? role.color : T.border}`,
                  transition: "all .45s cubic-bezier(.4,0,.2,1)",
                  position: "relative", background: role.bg,
                  boxShadow: isZoomed ? `0 30px 80px rgba(0,0,0,.5), 0 0 40px ${role.color}30` : "none",
                  opacity: isShrunk ? .55 : 1,
                }}
                onMouseEnter={() => setZoomed(role.key)}
                onMouseLeave={() => setZoomed(null)}
              >
                <div style={{ position: "relative", zIndex: 1, padding: "28px 24px", height: "100%", display: "flex", flexDirection: "column" }}>
                  <div style={{ width: 60, height: 60, borderRadius: 16, background: `${role.color}25`, border: `1.5px solid ${role.color}40`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 28, marginBottom: 16, transition: "transform .3s", transform: isZoomed ? "scale(1.12)" : "scale(1)" }}>
                    {role.icon}
                  </div>
                  <h3 style={{ fontFamily: "Syne", fontSize: 22, fontWeight: 800, marginBottom: 6, color: "#fff" }}>{role.label}</h3>
                  <p style={{ fontSize: 13, color: "rgba(255,255,255,.55)", lineHeight: 1.5 }}>{role.sub}</p>

                  {/* Login form - shown only when card is zoomed/hovered */}
                  {isZoomed && (
  <div style={{ marginTop: 24, animation: "fadeUp .35s ease" }}>
    <div style={{ marginBottom: 12 }}>
      <input
        type="email"
        placeholder={`${role.label.toLowerCase()}@email.com`}
        value={credentials[role.key].email}
        onChange={handleFieldChange(role.key, "email")}
        style={{
          width: "100%",
          background: "rgba(255,255,255,.08)",
          border: "1.5px solid rgba(255,255,255,.15)",
          borderRadius: 9,
          padding: "10px 14px",
          fontSize: 13,
          color: "#fff",
          outline: "none",
          fontFamily: "DM Sans",
        }}
        onFocus={(e) => (e.target.style.borderColor = role.color)}
        onBlur={(e) =>
          (e.target.style.borderColor = "rgba(255,255,255,.15)")
        }
      />
    </div>
    <div style={{ marginBottom: 16 }}>
      <input
        type="password"
        placeholder="Password"
        value={credentials[role.key].password}
        onChange={handleFieldChange(role.key, "password")}
        style={{
          width: "100%",
          background: "rgba(255,255,255,.08)",
          border: "1.5px solid rgba(255,255,255,.15)",
          borderRadius: 9,
          padding: "10px 14px",
          fontSize: 13,
          color: "#fff",
          outline: "none",
          fontFamily: "DM Sans",
        }}
        onFocus={(e) => (e.target.style.borderColor = role.color)}
        onBlur={(e) =>
          (e.target.style.borderColor = "rgba(255,255,255,.15)")
        }
      />
    </div>
    <button
      onClick={() => handleLoginClick(role.key)}
      disabled={loadingRole === role.key}
      style={{
        width: "100%",
        background: `linear-gradient(135deg, ${role.color}, ${role.color}CC)`,
        border: "none",
        color:
          role.key === "admin" || role.key === "parent" ? "#000" : "#fff",
        padding: "12px",
        borderRadius: 9,
        fontWeight: 800,
        fontSize: 14,
        cursor: "pointer",
        marginBottom: 12,
        fontFamily: "DM Sans",
        opacity: loadingRole === role.key ? 0.7 : 1,
      }}
    >
      {loadingRole === role.key
        ? "Logging in..."
        : `Login as ${role.label} →`}
    </button>
    <button
      onClick={() => setModal(role.key)}
      style={{
        width: "100%",
        background: "rgba(255,255,255,.06)",
        border: "1px solid rgba(255,255,255,.15)",
        color: "rgba(255,255,255,.6)",
        padding: "9px",
        borderRadius: 9,
        fontSize: 12,
        cursor: "pointer",
        fontFamily: "DM Sans",
      }}
    >
      New {role.label}? Register here
    </button>
  </div>
)}
                </div>
              </div>
            );
          })}
        </div>

        <div style={{ display: "flex", gap: 24, marginTop: 28, flexWrap: "wrap", justifyContent: "center" }}>
          {["← Back to Website", "Forgot Password?", "Need Help?", "Privacy Policy"].map(l => (
            <button key={l} onClick={l === "← Back to Website" ? onBack : undefined}
              style={{ background: "none", border: "none", color: T.muted, fontSize: 13, cursor: "pointer" }}
            >{l}</button>
          ))}
        </div>
      </div>

      {/* Registration Modal */}
      {modal && (
  <RegModal
    role={modal}
    onClose={() => setModal(null)}
    onSuccess={(authResponse) => {
      setModal(null);
      onLoginSuccess(authResponse); // log in immediately after register
    }}
  />
)}
    </div>
  );
};

export default LoginPage;
